import React from "react";
import {useState,useRef,useEffect} from "react";
 
function App() {
  let [text,setText] = useState("")
  let [list,setList] = useState(()=>
  {
    let data = localStorage.getItem("myList");
    if(data){
      return JSON.parse(data);
    }
    else{
      return [];
    }
  })
  let myRef = useRef(null)

  useEffect(()=>
  {
    localStorage.setItem("myList",JSON.stringify(list))

  },[list])

  let addHandler = ()=>
  {
    let obj = {
      id:Date.now(),
      text:text
    }
    setList([...list,obj])
    setText("")   
    myRef.current.focus()  
  }

  let deleteHandler = (id)=>{
    let newList = list.filter((e)=>{
      if(e.id != id) return true;
      
    });
    setList(newList)

  }

  let editHandler = (id,text)=>{
    let newText = prompt("Enter the new text for the task:",text);
    let newList = list.map((e)=>{
      if(e.id == id){
        e.text = newText;
      }
      return e;
    });
    setList(newList);

  }
  

  return(
    <div>

      <h1>Todo List</h1>
      <input type="text" value={text} ref={myRef} placeholder="Add a new task" onChange={(e)=>setText(e.target.value)}/>
      <button onClick={addHandler}>Add</button>
      <ul type="none">
        {list.map((obj)=>
        {
          return(
            <li key={obj.id}>
              <span>{obj.text}</span>
              <button onClick={()=>editHandler(obj.id,obj.text)}>Edit</button>
              <button onClick={()=>deleteHandler(obj.id)}>Delete</button>
            </li>
          )
        })}
      </ul>
      
    </div>
  )
}

export default App;